const CAT_DEFS = [
  { x: '6%',  y: '22%', size: 64, dur: 8.0,  delay: 0    },
  { x: '83%', y: '14%', size: 48, dur: 12.4, delay: -2.1 },
  { x: '13%', y: '70%', size: 56, dur: 10.2, delay: -1.3 },
  { x: '77%', y: '66%', size: 52, dur: 15.6, delay: -3.5 },
  { x: '46%', y: '80%', size: 44, dur: 6.8,  delay: -0.7 },
  { x: '90%', y: '44%', size: 60, dur: 16.6, delay: -4.1 },
  { x: '2%',  y: '48%', size: 46, dur: 9.4,  delay: -1.8 },
  { x: '60%', y: '30%', size: 50, dur: 11.8, delay: -2.9 },
];

function addCats(): void {
  removeCats();
  CAT_DEFS.forEach(d => {
    const wrap = document.createElement('div');
    wrap.innerHTML = CAT_SVG;
    const el = wrap.firstElementChild as SVGSVGElement;
    el.classList.add('nw-spinning-cat');
    // start invisible so the browser sets up compositing layers before we show them
    el.style.cssText = `left:${d.x};top:${d.y};width:${d.size}px;height:${d.size}px;` +
      `animation-duration:${d.dur}s;animation-delay:${d.delay}s;` +
      `opacity:0;transition:opacity 0.25s`;
    document.body.appendChild(el);
  });
  // double-rAF: let the browser paint one frame with the new layers, then fade in
  requestAnimationFrame(() => requestAnimationFrame(() => {
    document.querySelectorAll<SVGSVGElement>('.nw-spinning-cat')
      .forEach(el => { el.style.opacity = '0.6'; });
  }));
}

function removeCats(): void {
  document.querySelectorAll('.nw-spinning-cat').forEach(el => el.remove());
}

let matrixAnim: number | null = null;
let matrixResizer: (() => void) | null = null;

function startMatrixRain(): void {
  stopMatrixRain();

  const canvas = document.createElement('canvas');
  canvas.id = 'nw-matrix';
  canvas.style.cssText = 'position:fixed;top:0;left:0;width:100%;height:100%;z-index:0;pointer-events:none;opacity:0.22;';
  document.body.appendChild(canvas);

  const ctx = canvas.getContext('2d')!;
  const fontSize = 14;
  let drops: number[] = [];

  const resize = (): void => {
    canvas.width  = window.innerWidth;
    canvas.height = window.innerHeight;
    const cols = Math.floor(canvas.width / fontSize);
    while (drops.length < cols) drops.push(Math.floor(Math.random() * -60));
    drops.length = cols;
  };
  resize();
  window.addEventListener('resize', resize);
  matrixResizer = resize;

  let last = 0;
  const draw = (ts: number): void => {
    matrixAnim = requestAnimationFrame(draw);
    if (document.documentElement.classList.contains('nw-paused')) return;
    if (ts - last < 55) return; // ~18 fps — feels rain-like without hammering the GPU
    last = ts;

    ctx.fillStyle = 'rgba(13,13,13,0.12)';
    ctx.fillRect(0, 0, canvas.width, canvas.height);
    ctx.font = `${fontSize}px 'Courier New', monospace`;

    for (let i = 0; i < drops.length; i++) {
      if (drops[i] < 0) { drops[i]++; continue; }

      const char = String(Math.floor(Math.random() * 10));
      // head of the drop is near-white; body is matrix green
      ctx.fillStyle = drops[i] <= 1 ? 'rgba(200,255,200,0.95)' : 'rgba(0,255,65,0.85)';
      ctx.fillText(char, i * fontSize, drops[i] * fontSize);

      if (drops[i] * fontSize > canvas.height && Math.random() > 0.975) {
        drops[i] = Math.floor(Math.random() * -50);
      } else {
        drops[i]++;
      }
    }
  };
  matrixAnim = requestAnimationFrame(draw);
}

function stopMatrixRain(): void {
  if (matrixAnim !== null) { cancelAnimationFrame(matrixAnim); matrixAnim = null; }
  if (matrixResizer)       { window.removeEventListener('resize', matrixResizer); matrixResizer = null; }
  document.getElementById('nw-matrix')?.remove();
}

const VALID_THEMES = ['default', 'carbon', 'newspaper', 'terminal', 'beach', 'space', 'aurora', 'cyber', 'cats', 'rust'];

let pageSuggestions: string[] = [];

function getSuggestedTheme(): string | null {
  for (const name of pageSuggestions) {
    const q = name.trim().toLowerCase();
    const match = VALID_THEMES.find(t => t.startsWith(q));
    if (match) return match;
  }
  return null;
}

function annotateSuggestion(suggested: string | null): void {
  const sel = document.getElementById('nw-theme-select') as HTMLSelectElement;
  Array.from(sel.options).forEach(opt => {
    const base = opt.text.replace(' (site default)', '');
    opt.text = opt.value === suggested ? `${base} (site default)` : base;
  });
}

export function suggestTheme(names: string[]): void {
  pageSuggestions = names;
  const suggested = getSuggestedTheme();
  annotateSuggestion(suggested);
  const funEnabled = localStorage.getItem('nw-fun-themes') === 'true';
  if (suggested && !localStorage.getItem('nw-theme') && (funEnabled || !FUN_THEMES.includes(suggested))) {
    applyTheme(suggested);
  }
}

function applyTheme(theme: string): void {
  const sel = document.getElementById('nw-theme-select') as HTMLSelectElement;
  document.documentElement.setAttribute('data-theme', theme);
  sel.value = theme;
  if (theme === 'cats') addCats(); else removeCats();
  if (theme === 'terminal') startMatrixRain(); else stopMatrixRain();
}

export function applyAnimPaused(paused: boolean): void {
  document.documentElement.classList.toggle('nw-paused', paused);
}

const FUN_THEMES = ['cats', 'cyber'];

export function applyFunThemes(enabled: boolean): void {
  const sel = document.getElementById('nw-theme-select') as HTMLSelectElement;
  for (const opt of Array.from(sel.options)) {
    if (FUN_THEMES.includes(opt.value)) opt.hidden = !enabled;
  }
  if (!enabled && FUN_THEMES.includes(sel.value)) {
    applyTheme('default');
    localStorage.removeItem('nw-theme');
  }
}

// hamburger toggle
const hamburger = document.getElementById('nw-hamburger') as HTMLButtonElement;
const barMenu   = document.getElementById('nw-bar-menu') as HTMLDivElement;
hamburger.addEventListener('click', () => {
  const open = barMenu.classList.toggle('open');
  hamburger.setAttribute('aria-expanded', String(open));
});

// restore saved paused state on load
const savedPaused = localStorage.getItem('nw-paused') === 'true';
applyAnimPaused(savedPaused);

// theme picker
const savedTheme = localStorage.getItem('nw-theme');
if (savedTheme) applyTheme(savedTheme);
applyFunThemes(localStorage.getItem('nw-fun-themes') === 'true');
document.getElementById('nw-theme-select')!.addEventListener('change', (e: Event) => {
  const value = (e.target as HTMLSelectElement).value;
  applyTheme(value);
  localStorage.setItem('nw-theme', value);
});
